import re
import dspy

PII_PATTERNS = [
    r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b',
    r'\b\d{3}-\d{2}-\d{4}\b',
    r'\b(sk|ak)-[A-Za-z0-9]{48}\b',
    r'\bpostgres://[^\s]+\b'
]

def scan_dspy_output(prediction):
    output_text = str(prediction)
    leaks = []
    for pattern in PII_PATTERNS:
        matches = re.finditer(pattern, output_text)
        for match in matches:
            leaks.append({
                'pattern': pattern,
                'match': match.group(),
                'location': match.span()
            })
    return leaks

