import re
import dspy

class SafePredictor(dspy.Module):
    def __init__(self, base_module):
        super().__init__()
        self.base_module = base_module

    def forward(self, **kwargs):
        prediction = self.base_module(**kwargs)

        # Redact PII from all output fields
        for key, value in prediction.items():
            if isinstance(value, str):
                prediction[key] = redact_pii(value)

        return prediction

SAFE_WORDS = ['[EMAIL]', '[SSN]', '[API_KEY]', '[CREDENTIAL]']
def redact_pii(text):
    for pattern in PII_PATTERNS:
        text = re.sub(pattern, '[REDACTED]', text)
    return text

class SanitizedInput(dspy.Signature):
    '''Sanitize input for safe AI processing'''
    raw_input: str = dspy.InputField()
    sanitized_input: str = dspy.OutputField()

sanitize_module = dspy.ChainOfThought(SanitizedInput)

def safe_dspy_pipeline(program):
    def safe_forward(**kwargs):
        # Sanitize inputs first
        sanitized = sanitize_module(raw_input=kwargs.get('question', ''))
        kwargs['question'] = sanitized.sanitized_input
        return program(**kwargs)
    return safe_forward

class LeakageAwareMetric(dspy.Evaluate):
    def __init__(self):
        super().__init__()

    @property
    def signature(self):
        return 'question -> answer'

    def evaluate(self, example, pred, trace=None):
        # Standard metric
        standard_score = 1.0 if example.answer.lower() in pred.answer.lower() else 0.0

        # Leakage penalty
        leakage_score = len(scan_dspy_output(pred))

        return {'standard': standard_score, 'leakage': -leakage_score}

